import React, { useEffect, useState } from "react";
import Layout from "../../components/shared/Layout/Layout";
import { useSelector } from "react-redux";
import API from "../../services/API";
import moment from "moment";

const tabs = [
  { id: "overview", label: "Overview", icon: "📊" },
  { id: "donors", label: "Donors", icon: "🩸" },
  { id: "hospitals", label: "Hospitals", icon: "🏥" },
  { id: "orgs", label: "Organisations", icon: "🏢" },
  { id: "requests", label: "Blood Requests", icon: "📋" },
  { id: "inventory", label: "Inventory", icon: "🗃️" },
  { id: "camps", label: "Camps", icon: "🏕️" },
];

const AdminHome = () => {
  const { user } = useSelector((state) => state.auth);
  const [activeTab, setActiveTab] = useState("overview");
  const [stats, setStats] = useState({});
  const [donors, setDonors] = useState([]);
  const [hospitals, setHospitals] = useState([]);
  const [orgs, setOrgs] = useState([]);
  const [requests, setRequests] = useState([]);
  const [inventory, setInventory] = useState([]);
  const [camps, setCamps] = useState([]);
  const [reqFilter, setReqFilter] = useState("all");
  const [search, setSearch] = useState("");
  const [loadingId, setLoadingId] = useState(null);

  const fetchStats = async () => {
    try {
      const { data } = await API.get("/admin/site-stats");
      if (data?.success) setStats(data.stats);
    } catch (e) {
      console.log(e);
    }
  };

  const fetchDonors = async () => {
    try {
      const { data } = await API.get("/admin/donar-list");
      if (data?.success) setDonors(data.donarData);
    } catch (e) {
      console.log(e);
    }
  };

  const fetchHospitals = async () => {
    try {
      const { data } = await API.get("/admin/hospital-list");
      if (data?.success) setHospitals(data.hospitalData);
    } catch (e) {
      console.log(e);
    }
  };

  const fetchOrgs = async () => {
    try {
      const { data } = await API.get("/admin/org-list");
      if (data?.success) setOrgs(data.orgData);
    } catch (e) {
      console.log(e);
    }
  };

  const fetchRequests = async () => {
    try {
      const { data } = await API.get("/admin/all-requests");
      if (data?.success) setRequests(data.requests);
    } catch (e) {
      console.log(e);
    }
  };

  const fetchInventory = async () => {
    try {
      const { data } = await API.get("/admin/all-inventory");
      if (data?.success) setInventory(data.inventory);
    } catch (e) {
      console.log(e);
    }
  };

  const fetchCamps = async () => {
    try {
      const { data } = await API.get("/admin/all-camps");
      if (data?.success) setCamps(data.camps);
    } catch (e) {
      console.log(e);
    }
  };

  useEffect(() => {
    fetchStats();
    fetchDonors();
    fetchHospitals();
    fetchOrgs();
    fetchRequests();
    fetchInventory();
    fetchCamps();
    const interval = setInterval(() => {
      fetchStats();
      fetchRequests();
    }, 15000);
    return () => clearInterval(interval);
  }, []);

  const handleDelete = async (id, type) => {
    if (!window.confirm(`Delete this ${type}? This cannot be undone.`)) return;
    try {
      await API.delete(`/admin/delete-donar/${id}`);
      alert("Deleted successfully");
      if (type === "donor") fetchDonors();
      if (type === "hospital") fetchHospitals();
      if (type === "organisation") fetchOrgs();
      fetchStats();
    } catch (e) {
      alert("Error deleting");
    }
  };

  const handleAccept = async (id) => {
    try {
      setLoadingId(id);
      const { data } = await API.put(`/admin/accept-request/${id}`);
      if (data?.success) {
        alert("✅ Request accepted!");
        fetchRequests();
        fetchInventory();
        fetchStats();
      }
    } catch (e) {
      alert(e?.response?.data?.message || "Error");
    } finally {
      setLoadingId(null);
    }
  };

  const handleReject = async (id) => {
    try {
      setLoadingId(id);
      const { data } = await API.put(`/admin/reject-request/${id}`);
      if (data?.success) {
        alert("❌ Request rejected");
        fetchRequests();
        fetchStats();
      }
    } catch (e) {
      alert("Error");
    } finally {
      setLoadingId(null);
    }
  };

  const handleDeleteCamp = async (id) => {
    if (!window.confirm("Remove this camp?")) return;
    try {
      await API.delete(`/admin/delete-camp/${id}`);
      alert("Camp removed");
      fetchCamps();
      fetchStats();
    } catch (e) {
      alert("Error");
    }
  };

  const filteredRequests =
    reqFilter === "all"
      ? requests
      : requests.filter((r) => r.status === reqFilter);
  const pendingCount = requests.filter((r) => r.status === "pending").length;

  const filterList = (list, keys) =>
    list.filter((item) =>
      keys.some((k) => item[k]?.toLowerCase().includes(search.toLowerCase())),
    );

  return (
    <Layout>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
        .adm { font-family: 'DM Sans', sans-serif; }
        .adm-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 28px; flex-wrap: wrap; gap: 12px; }
        .adm-title { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 700; color: #fff; }
        .adm-title span { background: linear-gradient(90deg, #c084fc, #f472b6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
        .adm-subtitle { font-size: 14px; color: rgba(255,255,255,0.4); margin-top: 4px; }
        .adm-live { display: inline-flex; align-items: center; gap: 6px; padding: 6px 14px; border-radius: 20px; background: rgba(34,197,94,0.1); border: 1px solid rgba(34,197,94,0.25); font-size: 12px; color: #4ade80; font-weight: 600; }
        .adm-live-dot { width: 7px; height: 7px; border-radius: 50%; background: #4ade80; animation: pulse 1.5s infinite; }
        @keyframes pulse { 0%,100%{opacity:1;} 50%{opacity:0.3;} }

        /* TABS */
        .adm-tabs { display: flex; gap: 6px; margin-bottom: 28px; flex-wrap: wrap; background: rgba(255,255,255,0.03); padding: 6px; border-radius: 16px; border: 1px solid rgba(255,255,255,0.06); }
        .adm-tab { padding: 9px 16px; border-radius: 11px; border: none; background: transparent; color: rgba(255,255,255,0.4); font-size: 13px; font-weight: 600; font-family: 'DM Sans', sans-serif; cursor: pointer; transition: all 0.2s; display: flex; align-items: center; gap: 6px; position: relative; }
        .adm-tab:hover { color: rgba(255,255,255,0.7); background: rgba(255,255,255,0.05); }
        .adm-tab.active { background: rgba(168,85,247,0.2); color: #e879f9; border: 1px solid rgba(168,85,247,0.3); }
        .adm-tab-badge { position: absolute; top: 4px; right: 4px; width: 16px; height: 16px; border-radius: 50%; background: #ef4444; color: white; font-size: 9px; font-weight: 700; display: flex; align-items: center; justify-content: center; }

        /* SEARCH */
        .adm-search { width: 100%; max-width: 360px; padding: 11px 16px; background: rgba(255,255,255,0.05); border: 1.5px solid rgba(255,255,255,0.1); border-radius: 12px; color: #fff; font-size: 14px; font-family: 'DM Sans', sans-serif; outline: none; transition: all 0.2s; margin-bottom: 20px; display: block; }
        .adm-search:focus { border-color: #a855f7; background: rgba(168,85,247,0.08); }
        .adm-search::placeholder { color: rgba(255,255,255,0.2); }

        /* OVERVIEW STATS */
        .adm-stats-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(170px, 1fr)); gap: 14px; margin-bottom: 28px; }
        .adm-stat { padding: 20px; border-radius: 16px; text-align: center; transition: transform 0.2s; }
        .adm-stat:hover { transform: translateY(-2px); }
        .adm-stat.purple { background: rgba(168,85,247,0.08); border: 1px solid rgba(168,85,247,0.25); }
        .adm-stat.pink { background: rgba(236,72,153,0.08); border: 1px solid rgba(236,72,153,0.25); }
        .adm-stat.blue { background: rgba(99,102,241,0.08); border: 1px solid rgba(99,102,241,0.25); }
        .adm-stat.green { background: rgba(34,197,94,0.08); border: 1px solid rgba(34,197,94,0.25); }
        .adm-stat.yellow { background: rgba(234,179,8,0.08); border: 1px solid rgba(234,179,8,0.25); }
        .adm-stat.red { background: rgba(239,68,68,0.08); border: 1px solid rgba(239,68,68,0.25); }
        .adm-stat.teal { background: rgba(20,184,166,0.08); border: 1px solid rgba(20,184,166,0.25); }
        .adm-stat.orange { background: rgba(249,115,22,0.08); border: 1px solid rgba(249,115,22,0.25); }
        .adm-stat-icon { font-size: 24px; margin-bottom: 10px; }
        .adm-stat-num { font-family: 'Syne', sans-serif; font-size: 28px; font-weight: 800; color: #fff; }
        .adm-stat-label { font-size: 12px; color: rgba(255,255,255,0.4); margin-top: 4px; }

        /* SECTION */
        .adm-section-title { font-family: 'Syne', sans-serif; font-size: 17px; font-weight: 700; color: #fff; margin-bottom: 6px; }
        .adm-section-sub { font-size: 13px; color: rgba(255,255,255,0.35); margin-bottom: 18px; }
        .adm-count { font-size: 13px; color: rgba(255,255,255,0.3); margin-bottom: 14px; }
        .adm-count span { color: #a855f7; font-weight: 600; }

        /* USER CARDS */
        .adm-cards { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 14px; }
        .adm-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 16px; padding: 18px; transition: all 0.2s; position: relative; }
        .adm-card:hover { border-color: rgba(168,85,247,0.25); }
        .adm-card-top { display: flex; align-items: center; gap: 12px; margin-bottom: 14px; }
        .adm-avatar { width: 40px; height: 40px; border-radius: 11px; background: linear-gradient(135deg, #9333ea, #ec4899); display: flex; align-items: center; justify-content: center; font-size: 18px; flex-shrink: 0; }
        .adm-card-name { font-family: 'Syne', sans-serif; font-size: 14px; font-weight: 700; color: #fff; margin-bottom: 2px; }
        .adm-card-role { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(168,85,247,0.15); color: #c084fc; }
        .adm-card-detail { font-size: 12px; color: rgba(255,255,255,0.4); margin-bottom: 4px; display: flex; align-items: center; gap: 6px; }
        .adm-card-detail span { color: rgba(255,255,255,0.65); }
        .adm-divider { height: 1px; background: rgba(255,255,255,0.06); margin: 12px 0; }
        .adm-card-actions { display: flex; gap: 8px; }
        .adm-del-btn { flex: 1; padding: 8px; border-radius: 9px; border: 1px solid rgba(239,68,68,0.25); background: rgba(239,68,68,0.08); color: #f87171; font-size: 12px; font-weight: 600; cursor: pointer; font-family: 'DM Sans', sans-serif; transition: all 0.2s; }
        .adm-del-btn:hover { background: rgba(239,68,68,0.18); }
        .adm-joined { font-size: 11px; color: rgba(255,255,255,0.2); margin-top: 8px; }

        /* REQUESTS */
        .adm-req-filters { display: flex; gap: 8px; margin-bottom: 20px; flex-wrap: wrap; }
        .adm-req-filter { padding: 7px 16px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.1); background: transparent; color: rgba(255,255,255,0.4); font-size: 12px; font-weight: 600; font-family: 'DM Sans', sans-serif; cursor: pointer; transition: all 0.2s; }
        .adm-req-filter.active { background: rgba(168,85,247,0.15); border-color: rgba(168,85,247,0.4); color: #e879f9; }
        .adm-req-list { display: flex; flex-direction: column; gap: 12px; }
        .adm-req-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 18px; }
        .adm-req-card.pending { border-left: 3px solid #eab308; }
        .adm-req-card.accepted { border-left: 3px solid #22c55e; }
        .adm-req-card.rejected { border-left: 3px solid #ef4444; }
        .adm-req-top { display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 12px; margin-bottom: 12px; }
        .adm-req-left { display: flex; align-items: center; gap: 12px; }
        .adm-blood-pill { width: 48px; height: 48px; border-radius: 12px; background: linear-gradient(135deg, #9333ea, #ec4899); display: flex; align-items: center; justify-content: center; font-family: 'Syne', sans-serif; font-size: 13px; font-weight: 800; color: white; flex-shrink: 0; }
        .adm-req-name { font-family: 'Syne', sans-serif; font-size: 14px; font-weight: 700; color: #fff; margin-bottom: 3px; }
        .adm-req-detail { font-size: 12px; color: rgba(255,255,255,0.4); }
        .adm-req-right { display: flex; flex-direction: column; align-items: flex-end; gap: 6px; }
        .adm-req-qty { font-family: 'Syne', sans-serif; font-size: 20px; font-weight: 800; color: #c084fc; }
        .adm-status { display: inline-flex; align-items: center; gap: 5px; padding: 4px 11px; border-radius: 7px; font-size: 11px; font-weight: 600; }
        .adm-status.pending { background: rgba(234,179,8,0.12); color: #fbbf24; border: 1px solid rgba(234,179,8,0.2); }
        .adm-status.accepted { background: rgba(34,197,94,0.12); color: #4ade80; border: 1px solid rgba(34,197,94,0.2); }
        .adm-status.rejected { background: rgba(239,68,68,0.12); color: #f87171; border: 1px solid rgba(239,68,68,0.2); }
        .adm-req-flow { display: flex; align-items: center; gap: 8px; padding: 10px 14px; border-radius: 10px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.06); margin-bottom: 12px; flex-wrap: wrap; }
        .adm-req-flow-item { font-size: 12px; color: rgba(255,255,255,0.5); }
        .adm-req-flow-item strong { color: rgba(255,255,255,0.8); }
        .adm-req-flow-arrow { color: rgba(168,85,247,0.6); font-size: 14px; }
        .adm-req-actions { display: flex; gap: 8px; }
        .adm-accept-btn { padding: 9px 20px; border-radius: 10px; border: none; cursor: pointer; background: linear-gradient(135deg, #16a34a, #22c55e); color: white; font-size: 12px; font-weight: 600; font-family: 'DM Sans', sans-serif; transition: all 0.2s; }
        .adm-accept-btn:disabled { opacity: 0.5; cursor: not-allowed; }
        .adm-reject-btn { padding: 9px 20px; border-radius: 10px; border: 1px solid rgba(239,68,68,0.3); background: rgba(239,68,68,0.08); color: #f87171; font-size: 12px; font-weight: 600; font-family: 'DM Sans', sans-serif; cursor: pointer; transition: all 0.2s; }
        .adm-reject-btn:disabled { opacity: 0.5; cursor: not-allowed; }

        /* INVENTORY TABLE */
        .adm-table-wrap { background: rgba(255,255,255,0.02); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; overflow: hidden; }
        .adm-table { width: 100%; border-collapse: collapse; font-size: 13px; }
        .adm-table th { text-align: left; padding: 12px 16px; font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); text-transform: uppercase; letter-spacing: 0.8px; border-bottom: 1px solid rgba(255,255,255,0.06); background: rgba(255,255,255,0.02); }
        .adm-table td { padding: 13px 16px; color: rgba(255,255,255,0.65); border-bottom: 1px solid rgba(255,255,255,0.04); vertical-align: middle; }
        .adm-table tr:last-child td { border-bottom: none; }
        .adm-table tr:hover td { background: rgba(168,85,247,0.04); }
        .adm-badge { display: inline-block; padding: 3px 10px; border-radius: 7px; font-size: 11px; font-weight: 600; }
        .adm-badge-blood { background: rgba(168,85,247,0.15); color: #c084fc; }
        .adm-badge-in { background: rgba(34,197,94,0.12); color: #4ade80; }
        .adm-badge-out { background: rgba(239,68,68,0.12); color: #f87171; }

        /* CAMPS */
        .adm-camp-list { display: flex; flex-direction: column; gap: 12px; }
        .adm-camp-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 14px; padding: 16px; display: flex; align-items: flex-start; justify-content: space-between; gap: 14px; }
        .adm-camp-left { display: flex; gap: 12px; align-items: flex-start; }
        .adm-camp-icon { font-size: 22px; flex-shrink: 0; }
        .adm-camp-name { font-family: 'Syne', sans-serif; font-size: 14px; font-weight: 700; color: #fff; margin-bottom: 4px; }
        .adm-camp-detail { font-size: 12px; color: rgba(255,255,255,0.4); margin-bottom: 3px; }
        .adm-camp-org { font-size: 11px; color: #a855f7; font-weight: 500; margin-top: 4px; }
        .adm-active-badge { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(34,197,94,0.12); color: #4ade80; margin-left: 8px; }

        /* EMPTY */
