              </div>
              <div className="adm-stat orange">
                <div className="adm-stat-icon">🗃️</div>
                <div className="adm-stat-num">{stats.totalInventory || 0}</div>
                <div className="adm-stat-label">Inventory Records</div>
              </div>
            </div>
