                <button
                  style={{
                    background: "none",
                    border: "none",
                    color: "#c084fc",
                    cursor: "pointer",
                    fontWeight: 600,
                    fontFamily: "inherit",
                    fontSize: 13,
                  }}
                  onClick={() => setActiveTab("requests")}
                >
                  Review now →
                </button>
              </div>
            )}
            <div className="adm-section-title" style={{ marginBottom: 16 }}>
              📊 Quick Summary
            </div>
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 16,
              }}
