                  style={{
                    fontFamily: "Syne, sans-serif",
                    fontSize: 14,
                    fontWeight: 700,
                    color: "#fff",
                    marginBottom: 14,
                  }}
                >
                  👥 Users Breakdown
                </div>
                {[
                  ["🩸 Donors", stats.totalDonors, "#c084fc"],
                  ["🏥 Hospitals", stats.totalHospitals, "#818cf8"],
                  ["🏢 Organisations", stats.totalOrgs, "#f472b6"],
                ].map(([label, val, color]) => (
