                      {label}
                    </span>
                    <span
                      style={{
                        fontFamily: "Syne,sans-serif",
                        fontSize: 16,
                        fontWeight: 800,
                        color,
                      }}
                    >
                      {val || 0}
                    </span>
                  </div>
                ))}
              </div>
              <div
                style={{
                  background: "rgba(255,255,255,0.03)",
                  border: "1px solid rgba(255,255,255,0.07)",
                  borderRadius: 16,
                  padding: 20,
                }}
              >
                <div
                  style={{
                    fontFamily: "Syne, sans-serif",
                    fontSize: 14,
                    fontWeight: 700,
                    color: "#fff",
                    marginBottom: 14,
                  }}
