                  🩸 Blood Flow
                </div>
                {[
                  ["📥 Donated (IN)", stats.totalBloodIn, "#4ade80"],
                  ["📤 Used (OUT)", stats.totalBloodOut, "#f87171"],
                  [
                    "💾 Available",
                    (stats.totalBloodIn || 0) - (stats.totalBloodOut || 0),
                    "#c084fc",
                  ],
                ].map(([label, val, color]) => (
                  <div
                    key={label}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "space-between",
                      marginBottom: 10,
                    }}
                  >
                    <span
                      style={{ fontSize: 13, color: "rgba(255,255,255,0.5)" }}
                    >
                      {label}
                    </span>
                    <span
                      style={{
                        fontFamily: "Syne,sans-serif",
                        fontSize: 16,
                        fontWeight: 800,
                        color,
                      }}
                    >
                      {val || 0} ml
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}

        {/* ── DONORS ── */}
        {activeTab === "donors" && (
          <>
            <div className="adm-section-title">🩸 All Donors</div>
            <div className="adm-section-sub">
              View and delete donor accounts
            </div>
            <input
              className="adm-search"
              placeholder="🔍 Search by name or email..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className="adm-count">
              Showing{" "}
              <span>{filterList(donors, ["name", "email"]).length}</span> donors
