                    <div className="adm-card-detail">
                      ✉️ <span>{d.email}</span>
                    </div>
                    {d.phone && (
                      <div className="adm-card-detail">
                        📞 <span>{d.phone}</span>
                      </div>
                    )}
                    {d.address && (
                      <div className="adm-card-detail">
                        📍 <span>{d.address}</span>
                      </div>
                    )}
                    <div className="adm-divider" />
                    <div className="adm-card-actions">
                      <button
                        className="adm-del-btn"
                        onClick={() => handleDelete(d._id, "donor")}
