              className="adm-search"
              placeholder="🔍 Search by name or email..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className="adm-count">
              Showing{" "}
              <span>
                {filterList(hospitals, ["hospitalName", "email"]).length}
              </span>{" "}
              hospitals
