                      <div className="adm-card-detail">
                        📞 <span>{h.phone}</span>
                      </div>
                    )}
                    {h.address && (
                      <div className="adm-card-detail">
                        📍 <span>{h.address}</span>
                      </div>
                    )}
                    {h.website && (
                      <div className="adm-card-detail">
                        🌐 <span>{h.website}</span>
                      </div>
                    )}
                    <div className="adm-divider" />
                    <div className="adm-card-actions">
                      <button
                        className="adm-del-btn"
                        onClick={() => handleDelete(h._id, "hospital")}
                      >
                        🗑️ Delete Account
                      </button>
                    </div>
                    <div className="adm-joined">
                      Joined {moment(h.createdAt).fromNow()}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {/* ── ORGANISATIONS ── */}
